INSERT INTO song (id, title, lyrics, album_id) VALUES
(1, 'AVOID MYSELF', 'Тут нас двое, — только я и мой загон новый<br>Здесь нас двое, — только я и мой загон новый<br>Тут нас двое, — только я и мой загон новый<br>Здесь нас двое, — только я и мой загон новый<br><br>Прятался от Солнца, голос трупов у ворот<br>Я упал в водоворот, в пути невидимых частот<br>Кто смеялся надо мной — теперь забудет кислород<br>Вечно тёмный в облаках, себе я складываю гроб<br>Вою, будто бы я волк, кожа вся наоборот<br>Твари пали в оборот, сука открывает рот свой<br>У меня катана, ставлю палец на курок<br>Мой танец моих блейдов как урок<br>В поле почему я Бог? Соло почему ты плох?<br>Роли не играет, роль твоя хуже быть не может<br>Я испытываю Бога, пролетаю марафон боли<br>Мой самоконтроль воли, бой бензопилой, клоны<br>Выбираешь фейк позы, воешь, подо мной Луны<br>Выбираю быть болен, этот мегаполис пожирает мою душу<br>Твоё время не придёт, в этом мире обречён<br>Мусор гибнет подо мной-мной-мной<br><br>Тут нас двое, — только я и мой загон новый<br>Здесь нас двое, — только я и мой загон новый<br><br>Я бы мог бы утонуть в море, испытать холод<br>Вспомнишь ли меня когда опять мой след уходит?<br>Снова эта полоса, снова меня жизнь морит<br>Постоянно город этот тебе только жить губит<br>Моя жизнь горе, вечно занятой, сорри<br>Сам с собой в ссоре, ты не знаешь это чувство<br>Будто вечно не один в доме<br>Кто за нами наблюдает, когда засыпаю вновь ночью?<br>За мной повсюду коса, надо мною светит звезда<br>Твои я вижу глаза во сне, летит стрекоза во тьме<br>Я приказал, мне казалось убить меня<br>Ты рассказал сам себе, что ты значимый<br>Гроб среди могилы, я готовлюсь в оружейной<br>Одеваюсь в только чёрный и твой разум будет пленный<br>Прототип меня враждебен, целый день без поражений<br>Full неделя воскресений и мой разум будет пленный<br><br>Тут нас двое, — только я и мой загон новый<br>Здесь нас двое, — только я и мой загон новый<br>Тут нас двое, — только я и мой загон новый<br>Здесь нас двое, — только я и мой загон новый', 1),
(2, 'SHINIGAMI EYES', 'По проводам бегу я, по стеклу надо мной воет ретина<br>Она мне: Suki da daisuki da<br>Догони грань по осколкам зеркал<br>В знак веры мне нужны её shinigami eyes<br>Покажу ей kanku dai-dai, do you wanna die?<br>I m goin  super sonic style, cyber goin  punk<br>I got nine in my hand-hand<br>Shut your fuckin mouth-mouth<br>Break, ты ебаный mistake<br><br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes<br><br>Мои руки blade of tears, чувствуй fear<br>Запах крови в керосине, в микросхеме мир<br>Digital убийца, выхожу в эфир<br>Новый твой кумир — энергетический вампир<br>Yeah, I m goin for the kill (Yeah)<br>Она ведёт себя как live wire<br>Show me shinigami eyes<br>Тёмный, выбираю Team Dire<br>Она видит моё ФИО, shinigami eyes<br>Укусила руку, будто Крайт<br>Да, это snake bite<br><br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes<br>Она смотрит — shinigami eyes', 1),
(3, 'LAGUNA BLADE', 'Маска на лице, я испытываю rage<br>Со мной поколение, я бы умер, но мне лень<br>Твоя агрессия летальна, покрывает, словно тень<br>Эти души-души забираю в плен<br>Со мной ща Азула, называй меня лагуна<br>Мы ща крутим куклу вуду, мёртвый гуль, я, бля, акула<br>Курим руны, на мне Луны, мне не нужно больше духов<br>Бля, улыбка давит скулы, мы old schoolы, много шума<br>Подо мной горит лагуна<br><br>Подо мной горит лагуна<br>Подо мной горит лагуна<br>Подо мной горит лагуна<br> <br>Я кручу свой байонет и достаю лагуна-блейд<br>В стеше меркнет butterfly, надо мною стонет напряжение<br>Осознание себя, помоги закрыть глаза<br>Я забылся в небесах, мой каждый день уже сомнение<br><br>На моей руке чидори, я стою, ворота Тори<br>В голове всё на повторе, меня убивает током<br>Твои слёзы в мониторе и я слышу голоса<br>Я захватываю стиль, сука, посмотри в глаза<br>Затаи своё дыханье, пролетаю, как гроза<br>По моим венам только яд, совы никогда не спят<br>Этот сонный паралич и снова ты, — моя шиза<br>Тебе некуда бежать, подо мной горит лагуна<br><br>Подо мной горит лагуна<br>Подо мной горит лагуна<br>Подо мной горит лагуна<br> <br>Я кручу свой байонет и достаю лагуна-блейд<br>В стеше меркнет butterfly, надо мною стонет напряжение<br>Осознание себя, помоги закрыть глаза<br>Я забылся в небесах, мой каждый день уже сомнение', 1),
(4, 'blessed', 'He ll give us what we need<br>It may not be what you want<br><br>Голос в ушах — they talkin <br>Я здесь, я снова lock in<br>Я blessed, я снова проклят<br>Я снова проклят (cursed)<br>Я снова проклят (cursed)<br>Я снова проклят<br>Проклят, проклят<br><br>Эй, я…<br>На проводах я повисну<br>Останусь в цепи — это сети<br>Меня оставила в небе звезда<br>Теперь жду, чтобы ты меня blessed, эй<br>Blessed, эй, blessed, эй<br>Проклятый вечно на блэссе, эй<br>Проклятый вечно на блессе, эй<br>Порвал Balenci, по венам Dior<br>И я жду новый звон колокольни<br>Мой проклятый ритм — на блэссе<br>Мой новый поход уже в прессе<br>Двигаться будем в эклипсе<br>Сегодня окажется в гипсе<br>Семнадцать закатов — на пирсе<br>Бинтом обвиваются кисти<br>Эй, я — проклятый, вечно на блэссе<br>Эй, проклятый голос…<br><br>Голос в ушах — they talkin<br>Я здесь, я снова lock in<br>Я blessed, я снова проклят<br>Я снова проклят (cursed)<br>Я снова проклят (cursed)<br>Я снова проклят<br>Проклят, проклят<br><br>Vision в глазах, будто линзы<br>Дай видеть, пока они слепы<br>Так холодно, тени скользят<br>Like a whisper, leaving me deafened<br>No will to exist…<br>Эхо в моей голове, тихий шёпот во тьме<br>Linkin Park on my wrist<br>И я вновь опускаю Balenci на газ<br>В чёрной whip, ты лишь копия в поиске рефа<br>Death is is my bitch, huh<br>Чёрно-белый мир — мир по фэншую<br>Называю cursed blood — я рисую<br>Blood — звёзды на машине<br>Иней холодный, как Shiva<br>Машины вылетают с трассы<br>Fuck feelings, my pills — амбассадор стиля<br>Get bad-bad, у меня кровь по руке<br>Я хейчу опять, вновь чёрная blood<br><br>Я…<br>Я снова проклят<br>Я снова проклят<br>Я снова проклят<br>Я снова проклят', 2),
(5, 'wave', 'Aye, yuh<br>Resonance<br><br>И не ищи меня в сети, all mute, молчание — стиль<br>Сойти, убиться в пыль или остаться пылью<br>В лицо Sauvignon, Confetti, на красный — стак монеты<br>На чёрный — эту боль, и всю ту, что на пути<br>Update, V8 wait — Cadillac, я выше в Escalade<br>Останусь в тени, я смотрю на тебя, как в desolate<br>Небо цвета крови — это bloody blade, мой bloody blade<br>Bloody blade, мой bloody blade<br>Призрак — вечность, адреналин и мгновенность<br>Я вне себя от расстрела, ничтожество — неизбежно<br>Всё в красно-чёрном и белом, моих смертей — бесконечно<br>В глаза смотрю — нету ведома, wake up paralyzed, maybe<br><br>Wave, wave, wave, wave<br>Техника, вокруг дыханья<br>У меня ща нет дыханья <br>Остаюсь в кругу реальных<br>Волны ща качают здания<br>Wave, wave, wave, wave, wave<br><br>Дым заполняет меня полностью, взял много на себя<br>Мне надо сбросить с себя цепи, нужно показать ещё<br>Мне нужно паузу на центр, ты и я — внезапно смертны<br>Ты и я, ты и я — мне нравятся движения<br><br>Wave, wave, wave, wave<br>Техника, вокруг дыханья<br>У меня ща нет дыханья<br>Остаюсь в кругу реальных<br>Волны ща качают здания<br>Wave, wave, wave ', 2),
(6, 'bladyjerk', 'I m paralyzed, I m paralyzed<br>Я меняю эру, но будто нет эффекта<br>Вся земля как сфера, я кручу эти блейды<br>Аянами Рей, все трупы в этой секте<br>Паутины, цепи ну же, сука, ответь мне <br><br>Я убитый демон, ща восстану, где ты спишь сейчас?<br>Хочешь, я убью себя и выпущу наружу всё?<br>Каждый день я видел себя в цвете, но мне похуй ща<br>Я живу на солнце, моя clique в твоем доме ща<br>Я сжигаю договор и я кидаю бэнды<br>Полосы на мапе — я рисую тебе friend zone<br>Ебанутый dropout — вся бумага ball out<br>Я разбился в Benzo<br><br>I m paralyzed, I m paralyzed<br>Я меняю эру, но будто нет эффекта<br>Вся земля — как сфера, я кручу эти блейды<br>Аянами Рей, все трупы в этой секте<br>Паутины-цепи — ну же, сука, ответь мне <br><br>Memphis town — разряжаю в тело SCAR<br>Пауза, money flip, I just wanna go<br>Поджигаю skate-park, NFL<br>Поджигаю skate-park — NFL flip<br>Thousand dollar baby, от стакана — goin sleep<br>Разряжаю в дверь SCAR, высоко на пляж — high<br>Депрессивный вайб — die, uh<br><br>I just wanna ball out<br>I just wanna roll out<br>I just wanna ball out<br>I just wanna curse', 2),
(7, 'бледное лицо','MUPP broken your heart<br>Без сознания, без сознания<br>Без сознания, без сознания<br>Без сознания…<br><br>Жалость на лице роз<br>Ноль эмоций — zero banknotes<br>Dancing with the shadows<br>I m so empty, kill me slowly<br><br>Бледное лицо<br>Бледное лицо<br>Бледное лицо…<br><br>Без сознания<br>Без сознания<br>Без сознания…<br><br>Мой ад — это быть собой<br>Чёрное стекло<br>Мой ад — это быть собой<br>Чёрное стекло<br><br>Бледное лицо<br>Бледное лицо<br>Бледное лицо<br>Бледное лицо…' , 2),
(8, 'wake up','MUPP broken your heart<br><br>Pull my left foot up<br>I ain t even swaggin <br>Money talk — слушаю, как money talk<br>Тишина<br><br>Wake up, wake up<br>Wake up, wake up<br>Balenci, Balenci<br>Blood is on my Balenci<br>Pop molly<br>I dont feel it<br>Бледная луна сияет<br>Подожди, dont sleep now<br>Под цветами лезвий искры<br>Я сегодня призрак<br><br>Ты, я<br>Верю в Deagle, рядом два<br>Совы ночью спят — squad!<br>Отклик душ, в эквипе SCAR<br>Dont forget, I give you shine<br>Slow drive, feel high<br>Wake up everybody now<br>Высоко на небе — sky<br>Уже так темно — sleepy eyes<br><br>Wake up , wake up<br>Wake up, wake up<br><br>Swag, oh, swag, oh<br>Let go, let go<br>Тишина' , 2),
(9, 'tokyo trip','Я бы хотел уехать в Японию<br>На мне ща лежит малышка из Токио<br>Сука не знает, что зависает ща с проклятым<br>Сука не знает — aint nothing is stopping em<br>Wake up, call, зажигаю, похуй мне<br>Wake up, all, я стою ща во тьме<br>Wake up, hollow, вечер в огне<br>Проклятый город погружен во сне<br><br>Call ы на BlackBerry, голос в nightmare<br>Один в этой сфере, я в контуре дыма<br>У меня в стеше задодженый керри<br>Как полосы в карте, разгон в эти стрелы<br>Fucked up, fucked up<br>Блики движений, неоновый страх<br>Fucked up, fucked up<br>Смешанный дым, таю в тени, как мрак<br><br>Yuh, I been getting to a check, nigga, shut up<br>Nigga want smoke — hit him up like wassup?<br>Shit not done till a nigga get dug up<br>Call me livelife like a nigga got another<br>I been sipping on Habushu in Japan<br>Bad bitch gotta read the palm of my hand<br>If its night talk — let the blade swing, let it damage<br>Where a bad bitch sayin shit I dont understand, like:<br><br>Yeah, let go<br>Oh my<br>Yeah, yeah, yeah, yeah!<br>Yung Kami always send me with some fine shit<br>If it aint about a check then I decline it<br>Bad bitch givin me head when I recline it<br>Never second guess it — boy, we on that timing<br>Okay, yuh<br>cursed<br><br>Я бы хотел уехать в Японию<br>На мне ща лежит малышка из Токио<br>Сука не знает, что зависает ща с проклятым<br>Сука не знает — aint nothing is stopping em<br>Wake up, call, зажигаю, похуй мне<br>Wake up, all, я стою ща во тьме<br>Wake up, hollow, вечер в огне<br>Проклятый город погружен во сне<br><br>Swag in Japan bitch, you know where we at<br>Bitch, I m stacking that yen yeah, I stay in my path<br>Yams call me Young Cuh, so you know we gon spat<br>Like a Tokyo trip — its my foot on that gas<br>Hot Octane niggas never talking something round my game<br>Been the same nigga you know aint shit change<br>Let shit bust, I go bite that dust<br>We gon let shit bang!' , 2),
(10, 'mars','Отвези меня на Марс — как же похуй на бабки<br>На мне Rick Owens, Balenci — это лакшери тряпки<br>И двести в час — это медленно, в трансе<br>Отвези меня на Марс — как же похуй на бабки<br><br>И я курю стресс так опасно<br>Меня ща трогать опасно<br>Uno, dos, tres — и que pasa?<br>Две тыщи баксов на кассу<br>Иду до конца, прямо в массы<br>Сигареты в руках, а, а, а<br>Внутри — пустота, а, а, а<br><br>Эпицентр — центр, центр, центр<br>Сорок пятый вектор, вектор<br>Голос — эхо, эхо, эхо<br>Секта — hate me, hate me<br>Эпицентр — центр, центр, центр<br>Хаос, хаос, хаос, хаос<br>Время, время<br>Убиваю время, время<br>Убиваю — время<br><br>Марс, Марс<br>Хаос, хаос<br>Хаос, хаос<br><br>Отвези меня на Марс — как же похуй на бабки<br>На мне Rick Owens, Balenci — это лакшери тряпки<br>Отвези меня на Марс — как же похуй на бабки<br>На мне Rick Owens, Balenci — это лакшери тряпки<br><br>Забери меня на Марс, Марс, Марс', 2),
(11, 'aura','Вчера уснул и думал всё потеряно…<br>Но сегодня…<br>Я открыл глаза и мир мне должен<br><br>Крутятся их лица — выбор шлюх как в Омнитриксе<br>Деньги сменят твои руки, но я делаю их easy<br>Держу добера на цепи — он ведёт себя как дикий<br>Помоги себе убиться — вы все поголовно фрики<br><br>Двенадцать криков за корветом<br>Сколько вас пойдёт со мной?<br>На худи бирка от Chanel<br>Разбиты дёсна под губой<br>Со мной кастом-дрип<br>На мне Prada-дрип<br>Я сделал задний flip<br>Ты носишь second-hand<br>Покер-хенд — мои две пары band<br><br>Демон на баленсах, на мне два цвета<br>Я Shadow, Shadow blessed так сияет<br>Что над нами — моя аура<br>Сука, дай мне телефон мне нужно позвонить<br>Уебище, ты чё запродил? Ненавижу этот бит<br>Я будто паразит, я заберу профит<br>Меня от вас тошнит, они устроили мошпит<br>Моя аура…<br><br>Крутятся их лица — выбор шлюх как в Омнитриксе<br>Деньги сменят твои руки, но я делаю их easy<br>Держу добера на цепи — он ведёт себя как дикий<br>Помоги себе убиться — вы все поголовно фрики<br><br>И я хочу Ferrari<br>Твой шмот ща под ногами<br>Мой wave — это цунами<br>Со мной принцесса Нами<br>И я хочу Ferrari<br>Твой шмот ща под ногами<br>Мой wave — это цунами<br>Со мной принцесса Нами', 2),
(12, 'stitch!','Killa будто Stitch, yuh<br>Killa будто Stitch, okay<br>Killa будто Stitch, будто Stitch<br>Killa будто Stitch, будто Stitch<br>Killa будто Stitch, yuh-yuh<br><br>Бери всю кассу, бежать уже некуда<br>Быстрая тварь, ты — убита, я — Киллуа<br>Видно пси-блейды во тьме, будто ритуал<br>Моя соната — сирена на блесседе<br>Красный костюм и я в рейдже, как Кэссиди<br>Play на кассете, как души на vessele<br>Жму на reset, но всё равно в реккете<br>Выбью те брекеты — умерли в cemetery<br>Улыбка disturbed, корона из слёз<br>Атрибуты в агилу, я синий, как Морф<br>Танцую C-Walk на Porsche, как босс<br>На мне острые зубы разьебаны в кровь<br>Сегодня не умер, теряю контроль<br>Я кидаю бусты — это мой обезбол<br>Моя труппа — Фантомы, вижу в зеркале клона<br>Я в маске теней, как Ghost-Ghost!<br>Я беру нож и я как одержимый<br>Четыре руки, каждый ствол токсин<br>Мой скилл — VHS, заполняю магазин<br>Desolate на мне — я здесь один<br>Я беру нож — я опять одержимый<br>Порезы катаны, как порезы от шин<br>Змеи на мне — это Gucci, как Слизерин<br>Чёрный в глазах, моё тело как дым<br><br>Killa будто Stitch, yeah<br>Killa будто Stitch, yeah<br>Killa будто Stitch, yeah<br>Killa будто Stitch…<br><br>Killa будто Stitch, yuh-yuh<br>Killa будто Stitch, okay<br>Killa будто Stitch, будто Stitch<br>Killa будто Stitch, будто Stitch<br>Killa будто Stitch, yuh-yuh<br><br>Бегите, я конченый, трудно дышать<br>Я начал с нуля и закончу опять<br>Да, я как Стич, и нам нужно сыграть<br>Моя копия копии — сука, молчать<br>Видишь меня в отражении Sunder<br>Знаю, что в лёгких пламя — отдался боли<br>Показываю стиль, дыхание в норме<br>Небесный знак съебался с поля<br>Мои новые сферы меняют цвета<br>Это город Шибуя — кидаю meet up<br>Я не вижу ответа в глазах моих enemy<br>В руме меняю тебя через tab<br>Я знаю, что делаю<br>Мои руки немеют<br>На теле — порезы и раны<br>Мне трудно дышать<br>Чувствую, будто нирвана<br>Мне нечего дать', 2),
(13, 'aftershock','Почему я больше ничего не вижу?<br>Мои глаза наполнены слезами крови — я вас ненавижу<br>Ловлю снежинки ртом, все заебали пзидить<br>New bluelock поток — ударил<br>В моей катане…<br><br>Разрезал black New Rock от баса<br>В труп мой aftershock<br>Timelapse на теле и G-Shock<br>Я вытащил — на тебе шок<br>Мой нимбус, гало — это ток<br>И три вопроса — мой small talk<br>Последний — в тело<br>Кроссы Balenci, я снова сверху — мой поток<br>Украл твои деньги, украл твои деньги<br>Спиздил твой фейм, забрал твои кроссы<br>И даже будучи босым —<br>Вы будете верить сукиным вбросам<br>Сукины дети, сукины дети<br>Я так устал от этих ублюдков<br>Купите мне дом, подарите машину —<br>И я уеду на ней в Аргентину<br><br>Pa-pa-pa-pa — paparazzi<br>На счёт мне деньги — grazie<br>Patek, Patek, — это Bottega<br>Опять пустой, без тега<br>Pa-pa-pa-pa — paparazzi<br>На счёт—, на счёт мне деньги — grazie<br>С ножами в теле танцы —<br>Я теряю шансы<br><br>Прожил свою жизнь — теперь денаюсь<br>Моя душа на чёрный — pay the price<br>Скорость со мной — ща McLaren<br>В цвете bloody purple sky<br>На шее курса, paparazzi — rockstar<br><br>Я ща на Shibuya — это психодельный дрифт<br>Фейерверк, ты кружила, в картах дым — я как Гамбит<br>Я — ангел, демон, паразит<br>Подвеска — diamond, Beherit<br>Руки — ножи, Manhattan-вирус<br>Ты — последний прототип, эй<br><br>Pa-pa-pa-pa — paparazzi<br>На счёт мне деньги — grazie<br>Patek, Patek, — это Bottega<br>Опять пустой, без тега<br>Pa-pa-pa-pa — paparazzi<br>На счёт—, на счёт мне деньги — grazie<br>С ножами в теле танцы —<br>Я теряю шансы<br><br>С Cursedом в Париже<br>Боже, дай мне vision<br>Мои суки пизже<br>Mastercard и Visa<br>I got also cursed, aye<br>Lamborghini Mercy<br>I gotta be first, aye<br>Did paparazzi dirty-dirty<br><br>Pa-pa-pa-pa — paparazzi<br>На счёт мне деньги — grazie<br>Patek, Patek, — это Bottega<br>Опять пустой, без тега<br>Pa-pa-pa-pa — paparazzi<br>На счёт—, на счёт мне деньги — grazie<br>С ножами в теле танцы —<br>Я теряю шансы', 2),
(14, 'never enough','Ха-а, ха-а, а-а<br>Крики necromastery и вопли подо мной<br>Руки дезоляторы, shadow nevermore<br>Ха-а<br><br>Трипл рэйз в ебало, твоя сука вся течёт<br>Она говорит ей мало, но я продолжу ход<br>Твоё сердце так пылает, его превращаю в лед<br>Как Лелуш управляю этой сукой — она орёт<br>Я бегу ща как Соник, попробуй поймай<br>Эта сука не знает, как подойти — отступай<br>На мне ща куча дури и это не манта<br>Вдавил шб и таунт трайни, один из ста<br>Записал тебя в тетрадку и я не Ягами<br>Zero reasons to talk, ублюдки, это цунами<br>Я, бля, Тобирама — все бастарды за бортами<br>Я неуязвим, моя клятва — это синигами<br>Fear — это страх, а страх — это я<br>Под баффом агилы берсерк mode Киллуа<br>Sla-Sla-Slayer убийца, рефреш обновил я<br>Реквием в сердце — ты болью проникся<br>За спиной нет крыльев, но я лечу<br>Баттерфляй на руке и я его точу<br>Emotional emptiness — совсем не грущу<br>Why do you even try? Заживо сожру<br>Я-Я не под спидами, просто под хастой<br>Су-Су-Супер Сайян, so slow — это штрафной<br>Выпал крит, это не кристалис<br>Моб Психо сто, но мы не сыгрались<br><br>Зеницу Агацума — называй меня скорость<br>Меня не остановить, тревела на ноги полная готовность<br>See you later на полу следы от ног остались навсегда<br>Позади меня нет жара, only холода<br>Не оставлю тебе выбора, творя, бля, чудеса<br>Never enough даю те полчаса, убив всех enemy, ну да-да<br>Ха-а, продолжай, ха-а<br><br>Демоны в башке, рейзы на тебе<br>Кричишь от боли, приклонись судьбе<br>Поток Акаши, ты вставший на колени<br>Не посмел бы даже думать о замене<br>У меня нет кагуне, просто я ебанутый<br>Feel no pain — и я стал культом<br>Тысячи гулей узнают по никнейму<br>Чекай телеграм, там весь сквад Антейку<br>Если у тя бабочка — я не миссую<br>Если у тя мкб — ты вовсе не хитуешь<br>W/W — сияю ярче Иллидана<br>Парень ставит паузу и я достаю катану<br><br>Ха-а, ха-а, а-а<br>Крики Necromastery и вопли подо мной<br>Руки дезоляторы, shadow nevermore<br>Залетаю с автоматом, ставлю лазер коллиматор<br>Твоя тати — моя тати, со мной едет в Maserati<br>Фиолетовая shawty, её тело на кровати<br>Я снёс им всем ебало — это стиль аннигилятор<br>Третий глаз как шинигами, в темноте не вижу свет<br>Venom orb в моём пресете, замедляю в интернете<br>Вооружён зубами, я их отправлю на тот свет<br>Они стреляют в моё тело, мой armor бронежилет<br>Мо-Моя катана самехада — она поедает этих тварей<br>Холодает в моём теле, бью — я будто Гаара<br>Один hit по тебе — ты пропал с радара<br>Пустота в моей душе — я называю Сахара<br><br>Крики Necromastery и вопли подо мной<br>Руки дезоляторы, shadow nevermore', NULL),
(15, 'bankai','Я сейчас в форме, называй это банкай<br>Небесная цепь рассекает луну<br>Бегущий в тумане, dream тати хентай<br>Голос её меня тянет ко дну<br>Мои глаза закрывает бандана<br>И рядом со мной телефон и отрава<br>По тебе блейдом, Зангецу катаной<br>Свет в темноте словно блики Мираны<br>Я сейчас в форме, называй это банкай<br>Небесная цепь рассекает луну<br>Бегущий в тумане, dream тати хентай<br>Голос её меня тянет ко дну<br>Белое дерево, ледяная тропа<br>Холод пронзает твоё тело шипя<br>Идущий по воздуху поступью Айзена<br>Головы пустоши рушит душа<br><br>А-а, а-а, а-а, а-а<br>Я окружённый во тьме вижу свет<br>Это не frenzy, но я ща под момом<br>Девятый хвостатый, Расенсюрикеном<br>По телу несутся порезы и раны<br>Мой лик безобразен, скрываюсь под маской<br>Ярость Стокгольма, в этом файте Вайзарды<br>Из мрака сияют, будто пара квазаров<br>Hollow destroyer, погружённый в астрале<br>Бесконечная мана, я держу их в кошмаре<br>А-а, а-а, а-а, а-а<br>Открой глаза, я не исчез, твои догадки настолько убоги<br>Как Гриммджоу рассекаю всех тварей в потоке<br>Совсем не слышу я, вопли жестоки<br>Это не эффекты, просто банкай<br>Если дартс, то только смертельный<br>Под формой пустого Зангецу прицельно<br>Отбросив хасту юзаю Сонидо отдельно<br>Взмах клинком, настало твоё бремя<br>Уничтожаю всё это пространство и время<br>Видишь клыки на моём фэйсе?<br>Все мои фраги они only в процессе<br><br>Я сейчас в форме, называй это банкай<br>Небесная цепь рассекает луну<br>Бегущий в тумане, dream тати хентай<br>Голос её меня тянет ко дну<br>Мои глаза закрывает бандана<br>И рядом со мной телефон и отрава<br>По тебе блейдом, Зангецу катаной<br>Свет в темноте словно блики Мираны<br>Я сейчас в форме, называй это банкай<br>Небесная цепь рассекает луну<br>Бегущий в тумане, dream тати хентай<br>Голос её меня тянет ко дну<br>Белое дерево, ледяная тропа<br>Холод пронзает твоё тело шипя<br>Идущий по воздуху поступью Айзена<br>Головы пустоши рушит душа<br><br>Which means… I ll be king', NULL),
(16, 'killua','Основной инстинкт —<br>Ха, поебать, я psychokilla<br>Кинул цепи — всех убило<br>В телефоне triple zero, твои рофлы — очень мило<br>Я убийца Killua, Killua, Killua<br>Я убийца Killua, Killua, Killua<br>Psycho Ghoul, я кинул пулю этим сукам между глаз<br>Достаю свою катану, в моих лёгких only газ<br>Они кричат мне: Охуенный, вызвал в них ажиотаж<br>Визор вниз, вошедший в мрак, он звал меня в последний раз<br><br>Вижу схемы<br>Третий глаз на моём фэйсе, обвиваю всех цепями<br>Моя роза увядает, заколю типов шипами<br>Вижу схемы пред глазами, мои руки как Акамэ<br>Моя клика будто Золдик: все ложатся под ногами<br><br>Я убийца Killua, Killua, Killua<br>Я убийца Killua, Killua, Killua<br><br>Небесная арена, будто мы сцепились в лобби<br>Я эксперт в потоке нэна, вечно слышу твои вопли<br>Нету времени страдать, бегу вокруг касаний молний<br>Моё лицо залито кровью, быть свирепым — моё хобби<br>Уровень меж нами теперь слишком различен<br>Эта душа в твоём теле так обычна<br>Бьётся головой о стены, психика так вышла<br>Туша в чёрном худи для меня безразлична<br><br>Основной инстинкт —<br>Ха,поебать, я psychokilla<br>Кинул цепи — всех убило<br>В телефоне triple zero, твои рофлы — очень мило<br>Я убийца Killua, Killua, Killua<br>Я убийца Killua, Killua, Killua<br>Psycho Ghoul, я кинул пулю этим сукам между глаз<br>Достаю свою катану, в моих лёгких only газ<br>Они кричат мне:Охуенный, вызвал в них ажиотаж<br>Визор вниз, вошедший в мрак, он звал меня в последний раз<br><br>Вижу копии себя, как будто след от эхо ритма<br>Мои когти — веном-питан, их удар неотразим<br>Я не возлюблен в этом мире без нормального режима<br>Сука, да, я в этой маске — main причина эгоизма<br>Ten, ren, hatsu, бум!<br>Моя харизма — порождение садизма<br>Эта тати —Нефертити, чейзит вайб идеализма<br>На мне линк, он без кд, моя позиция закрыта<br>Мувы в тени под смоками, я не Варден, это шиза<br>В моей власти элементы, много крови на костюм<br>Этих блядей поразил, и я уже не слышу шум<br>Облик мрака, вечно в стате я стреляю наобум<br>Я юзаю — ten, ren, hatsu, бум!', NULL),
(17, 'quique','А, а, ага, тебя с quinque, или без, а, ага<br>Я ща достану до небес<br>Моя рука скрыла надрез<br>У-У-Убью с quinque, или без<br><br>Куча quinque в арсенале, не ебу, какой мне взять<br>Акаме блейды режут стены, не ебу, какой юзать<br>Под момом френзи мою ярость не унять<br>Два баттерфляя на руках, и мне не нужен Abyssal (А)<br>Squad по пятам, отрубаю, хм, кагуне<br>Брызг крови мне в глаза, сколопендра залезает мне<br>А, а, мысли в голове, в голове<br>Моя маска строит демона оскал, е, может быть, шиза, а, а<br><br>Коснулся шеи — рипер швы, из меня лезут сколопендры<br>Изъели черви всем глаза, остался труп без всех артерий<br>Т-Т-Т-Твоё тело в эпицентре, omnislash ем режу вены<br>В глазах светит блеск рапиры<br>Мне не нужны катаны, сука, мне нужны ножи<br>У меня ща клоны-клоны-клоны, и это миражи<br>Не нужны катаны, сука, мне нужны ножи, а<br>Совы тут летают надо мной, как визажи<br>Много крови, крови, крови, куски плоти подо мной<br>Эти совы сейчас в форме, Desert Eagle мой recoil<br>Scythe of vyse — сцепило руки этим сукам, ты не воин<br>Это кагуне-ринкаку, моё тело обладает<br>В венах clarity — всё тает, блейды quinque мне сияют<br>Как огни, я выше неба, в голове меня пугают<br>Я, бля, hunter ghoul, и похуй, если в голове стреляет<br>Hello, friend, я ебанутый, мой mind set тя испугает<br><br>Ага, ага, ага, много крови на мне<br>Ага, ага, на мне много-много крови, я не знаю, где мой quinque<br>Я считаю ебанутым себя<br><br>Куча quinque в арсенале, не ебу, какой мне взять<br>Акаме блейды режут стены, не ебу, какой юзать<br>Под момом френзи мою ярость не унять<br>Два баттерфляя на руках, и мне не нужен Abyssal (А)<br>Squad по пятам, отрубаю, хм, кагуне<br>Брызг крови мне в глаза, сколопендра залезает мне<br>А, а, мысли в голове, в голове<br>Моя маска строит демона оскал, е, может быть, шиза, а, а<br><br>Твоё Древо Аогири — цвета скарлет мои руки<br>По рукам татуировки — эти швы, мой скилл Акира, умираю ща от скуки<br>Мёртв внутри, как Такизава, мои блейды — это quinque<br>Я в Арате, фулл арморе, мои техники юзаю<br>Level блейда супер hard, игра с клинками, будто веер<br>Души мёртвых веет север, в этом лобби toxic waste<br>Порождаю, сука, месть, ты не забудешь мою ярость<br>Ага, ты не забудешь мою ярость, достаю свой арсенал<br>Эти слёзы по щекам твоим, я поедаю сталь<br>Я живее всех живых, но бля, внутри я suicide<br>Пролетаю мимо оппов, я кричу: Hello, what s up?', NULL),
(18, 'mana break','Mana Break, искры по пятам, достану dissimilate<br>Mana Break<br>Свет моих касаний станет холодней<br>Mana Break рассекает anyway<br><br>Сука будто в аниме, глаза — это Риннеган<br>На них повязка в стиле тёмный Иллидан<br>У меня нет имени, блейдами мотивирован<br>По лезвию бегущий годы жизни аннулировал<br>Кручу эту суку, это Beyblade<br>В моей голове delay, эй<br>Mana Void Disable, эй-эй<br>В моей голове delay, эй<br>Поглощаю ману<br>Сколопендры по экрану заполняют рану<br> Нажимаю манту<br>Вдруг нас стало трое, достаю катану<br>Триста шестьдесят, поворот назад<br>Улетел вперёд и я не знаю, где я<br>Я не знаю где, я не знаю, где я, а<br><br>Mana Break, искры по пятам, достану dissimilate<br>Mana Break<br>Свет моих касаний станет холодней<br>Mana Break рассекает anyway <br><br>Я в потоке боли, вечно Hikimori Kai<br>В тени крови shadow kage, напиши мне: Let me die<br>Встану в амулете, не покину этот рай<br>На моей цепи написано летай<br>Цепи-цепи-цепи, поражение летально<br>Все твои комменты подо мной — это банально<br>По глазам твоим кометы<br>Цепи-цепи-цепи, манапул твой на прицеле<br>Тающие сферы, мои блейды потемнели<br><br>Mana Break, искры по пятам, достану dissimilate<br>Mana Break<br>Свет моих касаний станет холодней<br>Mana Break рассекает anyway<br><br>Цепи-цепи-цепи, поражение летально<br>Все твои комменты подо мной — это банально<br>По глазам твоим кометы<br>Цепи-цепи-цепи, манапул твой на прицеле<br>Тающие сферы, мои блейды потемнели', NULL),
(19, 'fatality','Yeah, yeah, slowdown, calm down<br>Сука, run-run-run, я начинаю showtime<br>Стрик отдал, мой скин нуар<br>Луна в глазах full ti-i-i-me, ах<br>Мои fist ы все горят, мой каждый мув — это fatality<br>Убил всю твою клику в топе, нажимаю далее<br>Добил чела прикладом, я открыл ему brutality<br>Рисую цветом крови, чел, я Сальвадор Дали<br><br>Tekken fist ы, rage art — fatality<br>Fatality, X-Ray, fatality, lethality<br><br>Yeah, yeah, slowdown, calm down<br>Сука, run-run-run, я начинаю showtime<br>Моя арена — это кладбище, опыта немерено<br>Мой меч — это Экскалибур, сделал всё намерено<br>И тело не искали бы<br>Развеиваю мрак — это свет Nullifier<br>Вспыльчивый летаю — Supermarine Spitfire<br>Показал стиль, ударяю fire<br>Тёмный, будто dire<br><br>М, ах<br>Удар раската грома<br>Всюду блик от стаи молний<br>Лужи крови, переломы<br>Ультимейт уже исполнен<br>Разрезаю небеса<br>Сошёл на поле полный боли<br>По стопам моим завеса, в тени порождаю клонов<br><br>Yeah, yeah, slowdown, calm down<br>Сука, run-run-run, я начинаю showtime<br>Стрик отдал, мой скин нуар<br>Луна в глазах full ti-i-i-me, ах<br>Мои fist ы все горят, мой каждый мув — это fatality<br>Убил всю твою клику в топе, нажимаю далее<br>Добил чела прикладом, я открыл ему brutality<br>Рисую цветом крови, чел, я Сальвадор Дали<br><br>Мугай-рю объято flame ом, кручу Fury, как торнадо<br>С эпицентра ветер шторма, на клинках мой веном Хандзо<br>На цепях, кусаригама обвивает инфернально<br>Я вонзил в тебя кунай, мой удар будет фатальный<br><br>Kitana wins, flawless victory<br>Ha-ha-ha', NULL),
(20, 'new era','Ай-яй, остался тут один<br>Ай-яй, я связанный судьбой-ой<br>Остался тут один<br>Ай-яй, я связанный судь—, а<br><br>На мне jetpack — это путь вверх — Io<br>Моя new era-era<br>Кручу вокруг, словно я Юрнеро<br>Я неуязвим, на мне Linken s Sphere<br>Слышу overcharge — это моя new era<br>У, era-era<br>Вы все крипы, минус головы — Io<br>Полетел вверх — это матрица, Нео<br>На мне jetpack — это путь вверх — Io<br>Моя new era-era <br>Кручу вокруг, словно я Юрнеро<br>Я неуязвим,на мне Linken s Sphere<br>Слышу overcharge — это моя new era<br>У, era-era<br>Вы все крипы, минус головы — Io-Io-Io<br><br>Ай-яй, остался тут один<br>Ай-яй, я связанный судьбой-ой<br>Остался тут один<br>Ай-яй, я связанный—, а<br><br>На мне no vision, у меня mindset<br>Занимаю высоту — это моя ниша<br>Говоришь-говоришь-говоришь лишнее<br>На мне фиолетовый блик, ухожу в инвиз<br>На мне no vision, у меня есть миссия<br>У меня есть пламя, не могу пройти<br>Ты сгораешь тише, тише-тише<br><br>На мне jetpack — это путь вверх — Io<br>Моя new era-era<br>Кручу вокруг, словно я Юрнеро<br>Я неуязвим, на мне Linken s Sphere<br>Слышу overcharge — это моя new era<br>У, era-era <br>Вы все крипы, минус головы — Io<br>Полетел вверх — это матрица, Нео<br><br>Полетел вверх — это матрица—', NULL),
(21, 'METAMORPHOSIS 3','Сломанный ублюдок, я родился в рефлексии<br>If you wanna be a bitch, then I never wanna see ya<br>Я поставил ей диагноз — необходимость в терапии<br>All em people need us, cause they know I m a playa<br>Отражение во снах твоих, я сонный паралич<br>Моё касание летально, в сердце холод, будто Lich<br>Я порезался о стёкла, почему не вижу лиц?<br>В себе новое отличие я раздвоил, будто глитч<br>Как к тебе я отношусь — в твоём обличии очнусь<br>Снова мой метаморфоз, меня мучает невроз<br>Поток угроз, в страхе ловишь передоз, экран не показывает пульс<br>Скоро будет рост, скорость замедляет дождь, себя ощущаю lost<br>I can be a ghost, сука<br>I am never close, yeah<br>I can do the most, girl<br>Meta-metamorphosis<br>Never stoppin for a second<br>Gonna die like a red rose, black rose, fuck hoes?<br>N-N-Never overdose, I m a wild rose, white rose<br>Feelin comatose I wanna cut throats — Death Row<br>Мир, заточенный во лжи, снова сбил себе режим<br>Тебе хочется уйти, сука, просто не дыши<br>Расскажи, кем дорожишь, сука, тише, тише<br>Тише, тише, тише<br><br>Like, damn<br>Shawty said she love me, she delete, aint worth my time<br>You can throw away them minutes, lil baby, aint wastin mine<br>If you thinkin that you widdit lil shawty, then get in line<br>Cause I dont got time for the bitches<br>I m makin money, makin bread, lil bitch, I run to the riches<br>And I do not got time for friends, because they movin suspicious<br>I heard they always fuckin talkin, tell em play they position<br>And if you run up on me lonely, you gon need a physician, wait<br>I don t really wanna talk<br>Tell em watch where they speak<br>Better watch where you steppin, if you walkin into me<br>Better play your position if you cannot keep up to speed<br>And I feel like I m bigger, you just a part of the machine<br>Three fifty on the dash when I pull up in the whip<br>And I m huntin for a bag when I pull up with the clip<br>Motherfuckers always talkin, but they never sayin shit<br>Heard they lookin for a problem, motherfucker, dont trip<br>Dont trip, dont fall, I dont really wanna blame you<br>Heard they said that I was changin, but thats really what the fame do<br>Life changed, why the fuck would I still be the same? Dont<br>Motherfuckers always talkin, but I m chillin with the same mood<br><br>With the same mood<br>With the same mood<br>With the same mood', NULL),
(22, 'haunt','Where is this? When is this?<br>What is happening?<br>MUPP broken your heart<br>Да, да-а, ха-а<br>Haunt!<br><br>Ты забудешь этот день, как забыла всё, что было<br>В пустоте моей могила, километры shadow step-step-step<br>В темноте увидел друга, там, где умирает свет<br>Замедляю дифузами мои мысли, между нами связи нет<br>Не осталось больше душ, но вены чёрные, как тушь<br>Упали слёзы, будто вьюга я холодный<br>Слушай:<br><br>Haunted, haunted<br>On my mind, kill me now<br>I m alone like desolate<br>Wake up on shadow step<br><br>Haunted, haunted, haunted<br>I m haunted <br>Как мне всё отпустить?<br>Сумма кипит<br>Сумрак, дай мне уйти<br><br>Я нажимаю газ, дорогу в темноте не видно<br>Всё сливается в едино, я — активная защита<br>Мои фантомные боли переносят на картину<br>За окном метеоритный новый ливень, ты — орбита<br>И мечте моей не сбыться, ты забыта<br>Всё убито ради выгоды — обида<br>Мои тени, твои тени мне прокладывают путь<br>Слушай:<br>Haunted, haunted<br>On my mind, kill me now<br>I m alone like desolate<br>Wake up on shadow step<br><br>Haunted, haunted, haunted<br>I m haunted', NULL),
(23, 'supernxva','Yo, MXRACLE, maybe stop?<br>And I m not talking about obvious stuff, like one s an animal and one s a person or one has two legs and one has four. Form, ability and power; that s what s puzzling!<br><br>Мой hadouken: akuma, надо мною supernova<br>Ночью пропадают души, мои клоны стали совы<br>Карта знает мою сумму, под ногами вянут розы<br>Потеряйся в катакомбах — для тебя это не сложно<br>Голос поглощает глушь, в темноте я луч<br>Клетку наполняют души, пополняя список нужд<br>Отпускаю всё наружу, тело в мраке обнаружишь<br>Погибая в мире душ<br><br>Её глазки будто Луны, на спине горят ножи<br>Все друзья уже фантомы, мир пропитанный во лжи<br>Эти клоны — миражи, вы для меня стали чужие<br>Холодно внутри, вы для меня стали чужие<br>Её глазки будто Луны, на спине горят ножи<br>Все друзья уже фантомы, мир пропитанный во лжи<br>Эти клоны — миражи, вы для меня стали чужие<br>Холодно внутри, вы для меня стали чужие<br><br>Раскидал кунаи цвета «голубой неон»<br>Миллион на моей тишке, пауки, мы батальон<br>Ты собою заполняешь фон, дельнул в Ableton<br>Я уезжаю с похорон и понимаю, — это просто сон<br>Изоляция фотона, свет во мраке — supernova<br>Ты космическая буря, в моей власти, как у Бога<br>Каждый день я вижу рану, бля, сияние Subaru<br>Твоя смерть уже готова, Super Saiyan Goku, uh<br><br>Её глазки будто Луны, на спине горят ножи<br>Все друзья уже фантомы, мир пропитанный во лжи<br>Эти клоны — миражи, вы для меня стали чужие<br>Холодно внутри, вы для меня стали чужие<br>Её глазки будто Луны, на спине горят ножи<br>Все друзья уже фантомы, мир пропитанный во лжи<br>Эти клоны — миражи, вы для меня стали чужие<br>Холодно внутри, вы для меня стали чужие<br><br>Я с закрытыми глазами пролетаю над тобой<br>В голове незаглушимый, вечный у меня вой<br>Облака над мною кружат, собираясь, будто рой<br>И я уже не воскресаю, чтобы чувствовать боль', NULL),
(24, 'FRACTAL HORNS','На цепи драконы, соло ронин, сука, devil wanna die<br>Умирай в моём загоне, когда двери suicide<br>Я не вижу отражений, ливень убивает рай<br>Небо выжигает sky, kaya, у меня line<br><br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна-бездна-бездна<br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна, у меня лишь бездна-бездна<br><br>Я являюсь как из Ада, дух мертвей, чем Такизава<br>Мои блейды безобразны, превращают тебя в прах<br>Взгляд холодный, будто Skadi; закипает, будто лава<br>Моя ярость не погасла, вызывает в тебе страх<br>Ваши души забираю, сука смотрит — рассекаю<br>Мне судьба располагает, в этом поле преобладаю<br>Эти демоны взывают, я король из сердца Ада<br>Ваши души забираю, сука смотрит — рассекаю<br>Твоё имя высекаю, мой клинок как Мурасаме<br>Мои крылья: лунный свет, когда зияют — я сияю-сияю-сияю<br><br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна-бездна-бездна<br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна<br><br>Демон в голове, бля, я на выбор Такизава<br>Чё за шмот на те, уёбище? Паук на бирке ZARA<br>Восемь сеток kusaka6e, friendly fire, Columbine<br>Bye, мусор, мне на выбор zero ранг<br>Кручу эту суку, будто Beyblade<br>Я выношу Azimov AK<br>Прячусь в dissimilate, разбиты ёбла ваши In-game<br>Daedalus плечи, на мне руки E-Blade<br>Твоё имя высекаю, мой клинок как Мурасаме<br>Мои крылья: лунный свет, когда зияют — я сияю-сияю-сияю<br><br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна-бездна-бездна<br>У меня есть два цвета: чёрный или белый<br>На башке рога, сука, у меня лишь бездна<br>У меня есть два цвета: чёрный или белый<br>Выбирай, сука, у меня лишь бездна, бездна', NULL),
(25, 'waste','Once upon a time was a fool who thought he d find<br>Purpose in his life along the way<br>Don t you run and hide from the truth you desire<br>Everything that lives is gone to waste<br><br>Я давно умер, ты не сможешь понять<br>Сам себя не могу уже удержать<br>Ненавижу себя, я устал понимать<br>Остался один и перестал замечать<br>Твои холодные руки были огни<br>Ледяные губы были теплы<br>Твои нежные руки стали мои<br>На мне курса, я устал, помоги<br>В моих глазах темнота, ты утонешь в печали и уходишь ко дну<br>Разбитое зеркало, будто бы сердце, порежет мне руку, уходишь во тьму<br>Твои тёплые руки давно не огни, эти ледяные губы уже не теплы<br>Твои нежные руки уже не мои<br>Я сбросил курсу, демон жрёт изнутри<br><br>Everything that lives is gone to waste<br><br>Ты в моих руках как кукла, внутри холода и вьюга<br>Спутал провода от кукол, эти голоса по кругу<br>Я тебя терплю как стужу, но теперь я вновь простужен<br>Демоны мои наружу, я вижу пустоту<br><br>Я давно умер, ты не сможешь понять<br>Сам себя не могу уже удержать<br>Ненавижу себя, я устал понимать<br>Я остался один и перестал замечать<br>Твои холодные руки были огни<br>Ледяные губы были теплы<br>Твои нежные руки стали мои<br>На мне курса, я устал, помоги<br>В моих глазах темнота, ты утонешь в печали и уходишь ко дну<br>Разбитое зеркало, будто бы сердце, порежет мне руку, уходишь во тьму<br>Твои тёплые руки давно не огни, эти ледяные губы уже не теплы<br>Твои нежные руки уже не мои<br>Я сбросил курсу, демон жрёт изнутри<br><br>Эй, эй, эй<br>Everything that lives is gone to waste', NULL),
(26, 'blade of tears','Будто мой стиль, он цунами, накладывает fear<br>На мне ща куча блейдов, blade of tears, yeah<br>Мой бег — shukuchi, на руки клинки из слёз, yeah<br>На мне ща куча блейдов, blade of tears, yeah<br><br>Blade of tears, yeah<br>Blade of tears, yeah<br>Blade of tears, yeah<br>Blade of tears, yeah<br><br>Умер, и все такие Die-die-die<br>Кровавые кинжалы, fly-fly-fly<br>Плаксивые катаны by my side<br>Road to sky<br>Blade of tears, I m fallen <br>Кики, Рики Овенс<br>Лимитки sold out, blades out of me<br>Слёзы стали blades, на них revenge mode<br><br>Будто мой стиль, — он цунами, накладывает fear<br>На мне ща куча блейдов, blade of tears, yeah<br>Мой бег — shukuchi, на руки клинки из слёз, yeah<br>На мне ща куча блейдов, blade of tears, yeah<br><br>Blade of tears, yeah<br>Blade of tears, yeah<br>Blade of tears, yeah<br>Blade of tears, yeah<br><br>Huh, со мной ща full squad в SUV<br>Твои слёзы и крики в mp3<br>Die-die-die, три ножа вокруг тела<br>Fly-fly-fly, сука, new era<br>Blades of tears, я снова Юрнеро<br>Кручу планету как сфера<br>Поменял стиль, — это new era<br>У, era-era<br>Сука, я не забыл, тише-тише<br>Поменял время, поменял вайб<br>Суки всё ищут-ищут', NULL),
(27, 'lyin n dyin','lyin n dyin, MUPP broken your heart<br>Dyin  and lyin , terrified<br>Notice my eyes— cried out<br>Lost, and you re watching me die<br><br>Я растворяюсь, каюсь<br>Я так летаю, hi you. Lyin and dyin <br>Я пропадаю, numbers I m dialin <br>Я наблюдаю все твои прова—<br><br>Cu-Cursed world, в степень призрак, shot в упор<br>Этот trip — мой Париж, аварийка в Spyder Porsche<br>Мы на sundown, я в линзах Yves Saint Laurent<br>Только сорвал план — все мои мысли so high<br><br>Love it when I m high with you<br>Иногда мне кажется, я тону<br>Я найду нас, я найду нас<br>Я найду нас, я найду<br><br>Я растворяюсь, каюсь<br>Я так летаю, hi you. Lyin and dyin<br>Я пропадаю, numbers I m dialin<br>Я наблюдаю все твои провалы<br><br>Boom shakalaka!<br>I ll make you mine — шум, суки<br>Я здесь типа high, ты — ублюдок<br>Атмосфера light, light, light, light<br><br>Dyin and lyin , terrified<br>Notice my eyes— cried out<br>Lost, and you re watching me die', NULL),
(28, 'Madrid','Твой билет в Мадрид, смотри, как он горит<br>Итог — я псих на вид, меняй меня под стиль<br>Я твой билет в Мадрид, смотри, как он горит<br>Итог — я псих на вид, меняй меня под стиль<br>Удаляй<br><br>Если я умру в сети…<br>Хочешь видеть бэнды через Бэнды?<br>Медленно я убиваю сердце<br>Начинаю путать между enemy и friendly<br>Крылья мне мешают оставаться<br>Удали меня, чтобы не помнили факапы<br>Кажется мне грубым называть тебя фанатом<br>Кажется мне грубым называть тебя фанатом, эй What s up?<br><br>Твой билет в Мадрид, смотри, как он горит<br>Итог — я псих на вид, меняй меня под стиль<br>Я твой билет в Мадрид, смотри, как он горит<br>Итог — я псих на вид, меняй меня под стиль<br>Удаляй<br><br>Если я умру в сети…<br>Хочешь видеть бэнды через Бэнды?<br>Медленно я убиваю сердце<br>Начинаю путать между enemy и friendly<br>Крылья мне мешают оставаться<br>Удали меня, чтобы не помнили факапы<br>Кажется мне грубым называть тебя фанатом<br>Кажется мне грубым называть тебя фанатом, эй What s up?', NULL);
