-- Удаляем существующую таблицу rating (используем другое имя для колонки)
DROP TABLE IF EXISTS rating;

-- Создаем таблицу rating с правильным именем колонки
CREATE TABLE rating (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    rating_value INTEGER NOT NULL,  -- Изменено с value на rating_value
    user_id BIGINT REFERENCES users(id),
    song_id BIGINT REFERENCES song(id),
    album_id BIGINT REFERENCES album(id),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

